1	import { Test, TestingModule } from '@nestjs/testing';
2	
3	import { BigQueryService } from '@modules/bigquery/bigquery.service';
4	import { PopulateStyleCopurchasesCommand } from '@modules/cli/commands/populate-style-copurchases.command';
5	import { StyleCopurchasesService } from '@modules/db/style-copurchases/style-copurchases.service';
6	
7	jest.mock('@config/rollbar.config', () => ({
8		rollbar: {
9			debug: jest.fn(),
10			error: jest.fn(),
11			warning: jest.fn(),
12			info: jest.fn(),
13			wait: jest.fn((cb: () => void) => {
14				cb();
15			}),
16		},
17	}));
18	
19	describe('PopulateStyleCopurchasesCommand', () => {
20		let command: PopulateStyleCopurchasesCommand;
21		let mockBigQueryService: jest.Mocked<BigQueryService>;
22		let mockStyleCopurchasesService: jest.Mocked<StyleCopurchasesService>;
23		let processExitSpy: jest.SpyInstance;
24	
25		beforeEach(async () => {
26			jest.clearAllMocks();
27			jest.useFakeTimers();
28	
29			processExitSpy = jest.spyOn(process, 'exit').mockImplementation(() => {
30				return undefined as never;
31			});
32	
33			mockBigQueryService = {
34				fetchStyleCopurchases: jest.fn(),
35			} as unknown as jest.Mocked<BigQueryService>;
36	
37			mockStyleCopurchasesService = {
38				bulkInsert: jest.fn(),
39				clearExistingData: jest.fn(),
40			} as unknown as jest.Mocked<StyleCopurchasesService>;
41	
42			const module: TestingModule = await Test.createTestingModule({
43				providers: [
44					PopulateStyleCopurchasesCommand,
45					{ provide: BigQueryService, useValue: mockBigQueryService },
46					{ provide: StyleCopurchasesService, useValue: mockStyleCopurchasesService },
47				],
48			}).compile();
49	
50			command = module.get<PopulateStyleCopurchasesCommand>(
51				PopulateStyleCopurchasesCommand,
52			);
53		});
54	
55		afterEach(() => {
56			processExitSpy.mockRestore();
57			jest.useRealTimers();
58		});
59	
60		describe('run', () => {
61			it('should fetch data, truncate, and insert', async () => {
62				const mockRows = [
63					{ style_a_id: 100, style_b_id: 200, co_purchase_count: 5 },
64					{ style_a_id: 300, style_b_id: 400, co_purchase_count: 3 },
65				];
66				mockBigQueryService.fetchStyleCopurchases.mockResolvedValueOnce(mockRows);
67				mockStyleCopurchasesService.clearExistingData.mockResolvedValueOnce(undefined);
68				mockStyleCopurchasesService.bulkInsert.mockResolvedValueOnce(undefined);
69	
70				await command.run();
71	
72				expect(mockBigQueryService.fetchStyleCopurchases).toHaveBeenCalledTimes(1);
73				expect(mockStyleCopurchasesService.clearExistingData).toHaveBeenCalledTimes(1);
74				expect(mockStyleCopurchasesService.bulkInsert).toHaveBeenCalledWith([
75					{ styleIdA: 100, styleIdB: 200, copurchaseCount: 5 },
76					{ styleIdA: 300, styleIdB: 400, copurchaseCount: 3 },
77				]);
78			});
79	
80			it('should skip truncate and insert when BigQuery returns empty result', async () => {
81				mockBigQueryService.fetchStyleCopurchases.mockResolvedValueOnce([]);
82	
83				await command.run();
84	
85				expect(mockStyleCopurchasesService.clearExistingData).not.toHaveBeenCalled();
86				expect(mockStyleCopurchasesService.bulkInsert).not.toHaveBeenCalled();
87			});
88	
89			it('should exit with code 1 when BigQuery fails', async () => {
90				mockBigQueryService.fetchStyleCopurchases.mockRejectedValueOnce(
91					new Error('BQ error'),
92				);
93	
94				await command.run();
95	
96				expect(mockStyleCopurchasesService.bulkInsert).not.toHaveBeenCalled();
97				expect(processExitSpy).toHaveBeenCalledWith(1);
98			});
99	
100			it('should return early when isShuttingDown is true', async () => {
101				(command as unknown as { isShuttingDown: boolean }).isShuttingDown = true;
102	
103				await command.run();
104	
105				expect(mockBigQueryService.fetchStyleCopurchases).not.toHaveBeenCalled();
106			});
107	
108			it('should not log success when shutdown occurs after upsert', async () => {
109				const mockRows = [{ style_a_id: 100, style_b_id: 200, co_purchase_count: 5 }];
110				mockBigQueryService.fetchStyleCopurchases.mockResolvedValueOnce(mockRows);
111				mockStyleCopurchasesService.clearExistingData.mockResolvedValueOnce(undefined);
112				// eslint-disable-next-line @typescript-eslint/require-await
113				mockStyleCopurchasesService.bulkInsert.mockImplementation(async () => {
114					(command as unknown as { isShuttingDown: boolean }).isShuttingDown = true;
115				});
116	
117				await command.run();
118	
119				expect(mockStyleCopurchasesService.bulkInsert).toHaveBeenCalledTimes(1);
120			});
121	
122			it('should return early in catch block when shutting down during error', async () => {
123				// eslint-disable-next-line @typescript-eslint/require-await
124				mockBigQueryService.fetchStyleCopurchases.mockImplementation(async () => {
125					(command as unknown as { isShuttingDown: boolean }).isShuttingDown = true;
126					throw new Error('interrupted');
127				});
128	
129				await command.run();
130	
131				expect(processExitSpy).not.toHaveBeenCalledWith(1);
132			});
133		});
134	
135		describe('handleShutdown', () => {
136			it('should set isShuttingDown and exit with 0 when no current operation', async () => {
137				await (
138					command as unknown as { handleShutdown: (signal: string) => Promise<void> }
139				).handleShutdown('SIGTERM');
140	
141				expect((command as unknown as { isShuttingDown: boolean }).isShuttingDown).toBe(
142					true,
143				);
144				expect(processExitSpy).toHaveBeenCalledWith(0);
145			});
146	
147			it('should force exit when already shutting down', async () => {
148				(command as unknown as { isShuttingDown: boolean }).isShuttingDown = true;
149	
150				await (
151					command as unknown as { handleShutdown: (signal: string) => Promise<void> }
152				).handleShutdown('SIGTERM');
153	
154				expect(processExitSpy).toHaveBeenCalledWith(1);
155			});
156	
157			it('should wait for current operation and then exit', async () => {
158				(
159					command as unknown as { currentOperation: Promise<void> | null }
160				).currentOperation = Promise.resolve();
161	
162				await (
163					command as unknown as { handleShutdown: (signal: string) => Promise<void> }
164				).handleShutdown('SIGTERM');
165	
166				expect(processExitSpy).toHaveBeenCalledWith(0);
167			});
168	
169			it('should exit with 1 when current operation rejects', async () => {
170				(
171					command as unknown as { currentOperation: Promise<void> | null }
172				).currentOperation = Promise.reject(new Error('operation failed'));
173	
174				await (
175					command as unknown as { handleShutdown: (signal: string) => Promise<void> }
176				).handleShutdown('SIGINT');
177	
178				expect(processExitSpy).toHaveBeenCalledWith(1);
179			});
180	
181			it('should force exit on shutdown timeout', async () => {
182				let resolveOp: () => void;
183				(
184					command as unknown as { currentOperation: Promise<void> | null }
185				).currentOperation = new Promise<void>((resolve) => {
186					resolveOp = resolve;
187				});
188	
189				const shutdownPromise = (
190					command as unknown as { handleShutdown: (signal: string) => Promise<void> }
191				).handleShutdown('SIGTERM');
192	
193				jest.advanceTimersByTime(30000);
194	
195				expect(processExitSpy).toHaveBeenCalledWith(1);
196	
197				resolveOp!();
198				await shutdownPromise;
199			});
200		});
201	
202		describe('setupGracefulShutdown', () => {
203			it('should handle signal by calling handleShutdown', () => {
204				const handleShutdownSpy = jest.spyOn(
205					command as unknown as { handleShutdown: (signal: string) => Promise<void> },
206					'handleShutdown',
207				);
208				handleShutdownSpy.mockResolvedValue(undefined);
209	
210				process.emit('SIGHUP', 'SIGHUP');
211	
212				expect(handleShutdownSpy).toHaveBeenCalledWith('SIGHUP');
213				handleShutdownSpy.mockRestore();
214			});
215	
216			it('should handle uncaughtException by calling handleShutdown', () => {
217				const handleShutdownSpy = jest.spyOn(
218					command as unknown as { handleShutdown: (signal: string) => Promise<void> },
219					'handleShutdown',
220				);
221				handleShutdownSpy.mockResolvedValue(undefined);
222	
223				process.emit('uncaughtException', new Error('test uncaught'));
224	
225				expect(handleShutdownSpy).toHaveBeenCalledWith('SIGTERM');
226				handleShutdownSpy.mockRestore();
227			});
228	
229			it('should handle unhandledRejection by calling handleShutdown', () => {
230				const handleShutdownSpy = jest.spyOn(
231					command as unknown as { handleShutdown: (signal: string) => Promise<void> },
232					'handleShutdown',
233				);
234				handleShutdownSpy.mockResolvedValue(undefined);
235	
236				process.emit('unhandledRejection', 'test rejection', Promise.resolve());
237	
238				expect(handleShutdownSpy).toHaveBeenCalledWith('SIGTERM');
239				handleShutdownSpy.mockRestore();
240			});
241		});
242	});
