1	import { Logger } from '@nestjs/common';
2	import { Command, CommandRunner } from 'nest-commander';
3	
4	import { BigQueryService } from '@modules/bigquery/bigquery.service';
5	import { StyleCopurchasesService } from '@modules/db/style-copurchases/style-copurchases.service';
6	
7	import { CronJobExecution } from '@decorators/cron-job-execution.decorator';
8	
9	@Command({
10		name: 'populate-style-copurchases',
11		description: 'Fetch co-purchase data from BigQuery and update style_copurchases table',
12	})
13	export class PopulateStyleCopurchasesCommand extends CommandRunner {
14		private readonly logger = new Logger(PopulateStyleCopurchasesCommand.name);
15		private isShuttingDown = false;
16		private currentOperation: Promise<void> | null = null;
17	
18		constructor(
19			private readonly bigQueryService: BigQueryService,
20			private readonly styleCopurchasesService: StyleCopurchasesService,
21		) {
22			super();
23			this.setupGracefulShutdown();
24		}
25	
26		@CronJobExecution({ jobName: 'populate-style-copurchases' })
27		async run(): Promise<void> {
28			if (this.isShuttingDown) {
29				this.logger.warn('Command cancelled due to shutdown signal');
30				return;
31			}
32	
33			this.currentOperation = this.executePopulation();
34			await this.currentOperation;
35		}
36	
37		private async executePopulation(): Promise<void> {
38			try {
39				this.logger.log('Fetching co-purchase data from BigQuery...');
40				const rows = await this.bigQueryService.fetchStyleCopurchases();
41				this.logger.log(`Fetched ${rows.length} co-purchase pairs from BigQuery`);
42	
43				if (rows.length === 0) {
44					this.logger.warn(
45						'No co-purchase data returned from BigQuery — skipping truncate to prevent data loss',
46					);
47					return;
48				}
49	
50				const mapped = rows.map((row) => ({
51					styleIdA: row.style_a_id,
52					styleIdB: row.style_b_id,
53					copurchaseCount: row.co_purchase_count,
54				}));
55	
56				this.logger.log('Truncating existing co-purchase data...');
57				await this.styleCopurchasesService.clearExistingData();
58	
59				this.logger.log('Inserting co-purchase data...');
60				await this.styleCopurchasesService.bulkInsert(mapped);
61	
62				if (!this.isShuttingDown) {
63					this.logger.log(`Successfully populated ${mapped.length} style copurchase pairs`);
64					return;
65				}
66			} catch (error) {
67				if (this.isShuttingDown) {
68					this.logger.warn('Command interrupted during shutdown');
69					return;
70				}
71				this.logger.error(
72					`Failed to populate style copurchases: ${(error as Error).message}`,
73				);
74				process.exit(1);
75			} finally {
76				this.currentOperation = null;
77			}
78		}
79	
80		private setupGracefulShutdown(): void {
81			const signals: NodeJS.Signals[] = ['SIGTERM', 'SIGINT', 'SIGHUP', 'SIGQUIT'];
82	
83			signals.forEach((signal) => {
84				process.on(signal, () => {
85					void this.handleShutdown(signal);
86				});
87			});
88	
89			process.on('uncaughtException', (error) => {
90				this.logger.error(`Uncaught exception: ${error.message}`);
91				void this.handleShutdown('SIGTERM');
92			});
93	
94			process.on('unhandledRejection', (reason) => {
95				this.logger.error(`Unhandled rejection: ${String(reason)}`);
96				void this.handleShutdown('SIGTERM');
97			});
98		}
99	
100		private async handleShutdown(signal: string): Promise<void> {
101			if (this.isShuttingDown) {
102				this.logger.warn('Force shutdown requested, exiting immediately');
103				process.exit(1);
104			}
105	
106			this.logger.warn(`Received ${signal} signal, initiating graceful shutdown...`);
107			this.isShuttingDown = true;
108	
109			try {
110				if (this.currentOperation) {
111					this.logger.log('Waiting for current operation to complete...');
112	
113					const shutdownTimeout = setTimeout(() => {
114						this.logger.error('Graceful shutdown timeout, forcing exit');
115						process.exit(1);
116					}, 30000);
117	
118					await this.currentOperation;
119					clearTimeout(shutdownTimeout);
120				}
121	
122				this.logger.log('Graceful shutdown completed');
123				process.exit(0);
124			} catch (error) {
125				this.logger.error(`Error during shutdown: ${(error as Error).message}`);
126				process.exit(1);
127			}
128		}
129	}
